file_reader: Vérifie le contenu du fichier server.js pour confirmer sa création et son bon fonctionnement. => const express = require('express');
const app = express();
const port = 8080;\n\napp.get('/', (req, res) => {
  res.send('Hello');
});\n\napp.listen(port, () => {
  console.log(`Serveur démarré sur http://localhost:${port}`);
});
